#include<bits/stdc++.h>
using namespace std;
const long long N=300010,M=1200010;
long long n,t,ans[N],qcnt=1,t1[N],t2[N],id,v1[N],v2[N];
bool b[N];
struct node
{
    long long l,r,t,id;
}p[M],q[M];
set<long long> s;
long long lowbit(long long x)
{
    return x&-x;
}
void add(long long t[],long long v[],long long x,long long y)
{
    x++;
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        if(v[i]!=id)
        {
            v[i]=id;
            t[i]=0;
        }
        t[i]+=y;
    }
}
long long getsum(long long t[],long long v[],long long x)
{
    x++;
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        if(v[i]==id)
        {
            ans+=t[i];
        }
    }
    return ans;
}
void cdq(long long l,long long r)
{
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    long long i=l,j=mid+1,k=l;
    cdq(l,mid);
    cdq(mid+1,r);
    id++;
    while(j<=r)
    {
        while(i<=mid&&p[i].r>=p[j].r)
        {
            if(p[i].id<2)
            {
                add(t1,v1,p[i].l,p[i].t*p[i].id);
                add(t2,v2,p[i].l,p[i].id);
            }
            q[k++]=p[i++];
        }
        if(p[j].id>1)
        {
            ans[p[j].id]+=getsum(t2,v2,p[j].l-1)*p[j].t-getsum(t1,v1,p[j].l-1);
        }
        q[k++]=p[j++];
    }
    for(long long pos=0;pos<=r-k;pos++)
    {
        q[pos+k]=p[pos+i];
    }
    for(long long pos=l;pos<=r;pos++)
    {
        p[pos]=q[pos];
    }
}
char str[N];
int main()
{
    long long q;
    scanf("%lld%lld%s",&n,&q,str+1);
    for(long long i=1;i<=n;i++)
    {
        b[i]=str[i]-'0';
    }
    n++;
    for(long long i=0;i<=n;i++)
    {
        if(b[i]==0)
        {
            if(!s.empty())
            {
                p[++t]={(*(--s.end())),i,0,1};
            }
            s.insert(i);
        }
    }
    for(long long i=1;i<=q;i++)
    {
        long long x;
        scanf("%s%lld",str+1,&x);
        if(str[1]=='t')
        {
            b[x]^=1;
            if(b[x])
            {
                auto it=s.lower_bound(x);
                if(it!=s.begin())
                {
                    p[++t]={*prev(it),x,i,-1};
                    if(it!=(--s.end()))
                    {
                        p[++t]={*prev(it),*next(it),i,1};
                    }
                }
                if(it!=(--s.end()))
                {
                    p[++t]={x,*next(it),i,-1};
                }
                s.erase(it);
            }
            else
            {
                auto it=s.insert(x).first;
                if(it!=s.begin())
                {
                    p[++t]={*prev(it),x,i,1};
                    if(it!=(--s.end()))
                    {
                        p[++t]={*prev(it),*next(it),i,-1};
                    }
                }
                if(it!=(--s.end()))
                {
                    p[++t]={x,*next(it),i,1};
                }
            }
        }
        else
        {
            long long y;
            scanf("%lld",&y);
            p[++t]={x,y,i,++qcnt};
        }
    }
    cdq(1,t);
    for(long long i=2;i<=qcnt;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
